SELECT injury_type, injury_date
FROM injuries
ORDER BY injury_date DESC;

SELECT AVG(julianday(return_date) - julianday(injury_date)) AS average_recovery_time, injury_type
FROM injuries
GROUP BY injury_type;

SELECT COUNT(*) AS number_of_sprains
FROM injuries
WHERE injury_type = 'sprain';

SELECT COUNT(injury_id) AS injury_count
FROM injuries
WHERE game_id = 0;

SELECT SUM(julianday(return_date) - julianday(injury_date)) AS total_fracture_duration
FROM injuries
WHERE injury_type = 'Fracture';

SELECT injury_type, return_date
FROM injuries
WHERE injury_id = 1;

SELECT COUNT(*) AS injury_count
FROM injuries
WHERE game_id = 1;
